local function tq(tE,tv)
    if tv==nil then
        return false
    end
    if #tE~=#tv then
        return false
    end
    do
        local k2=0
        local hY=false
        while true do
            if hY then
                k2=k2+1
            else
                hY=true
            end
            if not(k2<#tE) then
                break
            end
            if tE[k2+1]==tv[k2+1] then
                continue
            end
            return false
        end
    end
    return true
end
return {areDepsEqual=tq}
